def calculate_error_rate(actual, predicted):
    if not isinstance(actual, list) or not isinstance(predicted, list):
        raise TypeError("Inputs 'actual' and 'predicted' must be lists.")

    if len(actual) != len(predicted):
        raise ValueError("Inputs 'actual' and 'predicted' must have the same length.")

    if not actual:
        return 0.0

    errors = 0
    for i in range(len(actual)):
        if actual[i] != predicted[i]:
            errors += 1

    return errors / len(actual)
